  it('should map API response and parse string values', () => {
    const mockResponse: ParameterPointsProgramResponse[] = [
      {
        category: 'saiba mais',
        value: JSON.stringify({
          categories: [
            {
              category: 'Pontos',
              questions: [
                {
                  question: 'Question 1',
                  answer: 'Answer 1',
                },
              ],
              order: 1,
              icon: 'icon-benefits',
            },
            {
              category: 'Pedidos',
