├── models/
│   ├── airlineMiles.model.ts
│   ├── parameter.model.ts
│   ├── permission.model.ts
│   ├── extract.model.ts
│   └── index.ts                    ← Exports all models
├── repository/                     ← Optional (only for complex domains)
│   ├── parameter.repository.ts    ← Data mapping/transformation
│   ├── extract.repository.ts
│   ├── permission.repository.ts   ← Optional (not used by permission)
│   └── index.ts                    ← Exports all repositories
├── services/
│   ├── airlineMiles.service.ts
│   ├── parameter.service.ts
│   ├── extract.service.ts
│   ├── permission.service.ts
│   └── index.ts                    ← Exports all services
├── store/
│   ├── airlineMiles.store.ts
│   ├── parameter.store.ts
│   ├── extract.store.ts
│   ├── permission.store.ts
│   ├── slices.ts                   ← ROOT STORE INTEGRATION
│   └── index.ts                    ← Exports all stores + RootStore type
├── hooks/
│   ├── useAirlineMiles.ts         ← Service hooks (optional)
│   ├── usePermission.ts
│   └── index.ts                    ← Exports selected hooks only
└── index.ts                        ← Main public API
```

---

### **2. Barrel Files (index.ts) Updates Required**

