### **5. Domain Layer Details**

#### **models/{domain}.model.ts**
Defines all TypeScript contracts for the domain:
```typescript
// Types for API request/response
export type {RequestType, ResponseType};

// Types for store state and actions
export type {DomainState, DomainActions};

// Enums (if needed)
export enum DomainStatus {
  IDLE = 'idle',
  LOADING = 'loading',
  SUCCESS = 'success',
  ERROR = 'error',
}

// Constants
export const DOMAIN_PARAMS = {...};
```

#### **api/{domain}.api.ts**
Raw HTTP client with no business logic:
```typescript
class DomainApi {
  async getResource(params): Promise<ResponseType> {
    const response = await api.get<ResponseType>('/endpoint');
    return response.data;
  }
}
export const domainApi = new DomainApi();
```

#### **repository/{domain}.repository.ts** (optional, only if needed)
Data transformation and mapping:
```typescript
export function mapDomainResponse(raw: RawType): DomainType {
  // Transform, parse, aggregate
  return transformed;
}
```

#### **services/{domain}.service.ts**
Business logic orchestration:
```typescript
class DomainService {
  async getResource(params): Promise<DomainType> {
    // Call repository/api, apply business rules
    return domainApi.getResource(params);
  }
}
export const domainService = new DomainService();
```

#### **store/{domain}.store.ts**
Zustand slice with actions:
```typescript
export type DomainSlice = {
  domain: DomainState;
  domainActions: DomainActions;
};

export const createDomainSlice: StateCreator<DomainSlice, [], [], DomainSlice> = (set) => ({
  domain: initialState,
  domainActions: {
    setStatus: (status) => set(/* ... */),
    setData: (data) => set(/* ... */),
    reset: () => set(/* ... */),
  },
});
```

#### **hooks/use{Domain}.ts** (optional)
Service hook combining state + actions:
```typescript
export const use{Domain} = () => {
  const domain = useRootStore(useShallow((state) => state.domain));

  const fetchData = useCallback(async () => {
    // Call service, update store via actions
  }, []);

  return { ...domain, fetchData };
};
```

